CREATE EXTENSION IF NOT EXISTS "pgcrypto";
CREATE EXTENSION IF NOT EXISTS pg_trgm;
DO $$ BEGIN CREATE TYPE public.employment_type AS ENUM ('PNS','PPPK','PPPK_PW','NON_ASN','THL'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

ALTER TABLE public.profiles
  ADD COLUMN IF NOT EXISTS requested_role public.app_role,
  ADD COLUMN IF NOT EXISTS verification_status text DEFAULT 'pending_verification',
  ADD COLUMN IF NOT EXISTS verification_method text,
  ADD COLUMN IF NOT EXISTS rejected_at timestamptz,
  ADD COLUMN IF NOT EXISTS rejected_by uuid,
  ADD COLUMN IF NOT EXISTS rejection_reason text,
  ADD COLUMN IF NOT EXISTS alamat text,
  ADD COLUMN IF NOT EXISTS jabatan_id uuid,
  ADD COLUMN IF NOT EXISTS employment_type public.employment_type;
ALTER TABLE public.profiles DROP CONSTRAINT IF EXISTS profiles_verification_status_chk;
ALTER TABLE public.profiles ADD CONSTRAINT profiles_verification_status_chk CHECK (verification_status IS NULL OR verification_status IN ('pending','pending_verification','pending_superadmin_approval','verified','rejected','unverified'));

CREATE TABLE IF NOT EXISTS public.master_jabatan (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), kode text UNIQUE, nama text NOT NULL, kategori text, pangkat_min text, golongan_min text, urutan integer DEFAULT 0 NOT NULL, aktif boolean DEFAULT true NOT NULL, created_at timestamptz DEFAULT now() NOT NULL, updated_at timestamptz DEFAULT now() NOT NULL);
GRANT SELECT, INSERT, UPDATE, DELETE ON public.master_jabatan TO authenticated; GRANT SELECT ON public.master_jabatan TO anon; GRANT ALL ON public.master_jabatan TO service_role; ALTER TABLE public.master_jabatan ENABLE ROW LEVEL SECURITY;
CREATE TABLE IF NOT EXISTS public.branding (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), key text UNIQUE NOT NULL, value jsonb DEFAULT '{}'::jsonb NOT NULL, updated_at timestamptz DEFAULT now() NOT NULL, updated_by uuid);
GRANT SELECT, INSERT, UPDATE, DELETE ON public.branding TO authenticated; GRANT ALL ON public.branding TO service_role; ALTER TABLE public.branding ENABLE ROW LEVEL SECURITY;
