GRANT SELECT, INSERT, UPDATE, DELETE ON public.aset_nilai_buku TO authenticated; GRANT ALL ON public.aset_nilai_buku TO service_role; ALTER TABLE public.aset_nilai_buku ENABLE ROW LEVEL SECURITY;
CREATE TABLE IF NOT EXISTS public.payroll_periods (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), opd_id uuid, tahun integer NOT NULL, bulan integer NOT NULL, locked_at timestamptz, locked_by uuid, unlocked_at timestamptz, unlocked_by uuid, catatan text, created_at timestamptz DEFAULT now() NOT NULL, updated_at timestamptz DEFAULT now() NOT NULL);
GRANT SELECT, INSERT, UPDATE, DELETE ON public.payroll_periods TO authenticated; GRANT ALL ON public.payroll_periods TO service_role; ALTER TABLE public.payroll_periods ENABLE ROW LEVEL SECURITY;
CREATE TABLE IF NOT EXISTS public.notifications (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), user_id uuid NOT NULL, tipe text NOT NULL, judul text NOT NULL, body text, link text, meta jsonb DEFAULT '{}'::jsonb, dibaca boolean DEFAULT false NOT NULL, created_at timestamptz DEFAULT now() NOT NULL);
GRANT SELECT, INSERT, UPDATE, DELETE ON public.notifications TO authenticated; GRANT ALL ON public.notifications TO service_role; ALTER TABLE public.notifications ENABLE ROW LEVEL SECURITY;
CREATE TABLE IF NOT EXISTS public.overtime_requests (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), user_id uuid NOT NULL, opd_id uuid, tanggal date NOT NULL, jam_mulai time NOT NULL, jam_selesai time NOT NULL, alasan text, status text DEFAULT 'pending' NOT NULL, approved_by uuid, approved_at timestamptz, catatan_approval text, created_at timestamptz DEFAULT now() NOT NULL, updated_at timestamptz DEFAULT now() NOT NULL);
GRANT SELECT, INSERT, UPDATE, DELETE ON public.overtime_requests TO authenticated; GRANT ALL ON public.overtime_requests TO service_role; ALTER TABLE public.overtime_requests ENABLE ROW LEVEL SECURITY;
CREATE TABLE IF NOT EXISTS public.pengajuan_izin (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), user_id uuid NOT NULL, opd_id uuid, jenis text NOT NULL, dari date NOT NULL, sampai date NOT NULL, alasan text, lampiran_url text, status text DEFAULT 'pending' NOT NULL, approved_by uuid, approved_at timestamptz, catatan_approval text, mengurangi_saldo boolean DEFAULT false NOT NULL, saldo_terpotong integer DEFAULT 0 NOT NULL, created_at timestamptz DEFAULT now() NOT NULL, updated_at timestamptz DEFAULT now() NOT NULL);
GRANT SELECT, INSERT, UPDATE, DELETE ON public.pengajuan_izin TO authenticated; GRANT ALL ON public.pengajuan_izin TO service_role; ALTER TABLE public.pengajuan_izin ENABLE ROW LEVEL SECURITY;
CREATE TABLE IF NOT EXISTS public.permissions (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), code text UNIQUE NOT NULL, label text NOT NULL, kategori text DEFAULT 'general' NOT NULL, description text, created_at timestamptz DEFAULT now() NOT NULL);
GRANT SELECT, INSERT, UPDATE, DELETE ON public.permissions TO authenticated; GRANT ALL ON public.permissions TO service_role; ALTER TABLE public.permissions ENABLE ROW LEVEL SECURITY;
CREATE TABLE IF NOT EXISTS public.permohonan_berkas (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), permohonan_id uuid NOT NULL, storage_path text NOT NULL, jenis text, nama_file text, size_bytes bigint, uploaded_by uuid, created_at timestamptz DEFAULT now() NOT NULL);
GRANT SELECT, INSERT, UPDATE, DELETE ON public.permohonan_berkas TO authenticated; GRANT ALL ON public.permohonan_berkas TO service_role; ALTER TABLE public.permohonan_berkas ENABLE ROW LEVEL SECURITY;
CREATE TABLE IF NOT EXISTS public.rate_limit_hits (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), scope text NOT NULL, subject text NOT NULL, window_start timestamptz NOT NULL, count integer DEFAULT 1 NOT NULL, last_hit_at timestamptz DEFAULT now() NOT NULL);
GRANT SELECT, INSERT, UPDATE, DELETE ON public.rate_limit_hits TO authenticated; GRANT ALL ON public.rate_limit_hits TO service_role; ALTER TABLE public.rate_limit_hits ENABLE ROW LEVEL SECURITY;
